# Windows Dark Title Bar
def enable_windows_dark_titlebar(window):
    try:
        import ctypes
        from ctypes import byref, sizeof, c_int

        window.update_idletasks()
        hwnd = window.winfo_id()

        value = c_int(1)

        # Windows 11 / Windows 10 20H1+
        try:
            ctypes.windll.dwmapi.DwmSetWindowAttribute(
                hwnd, 20, byref(value), sizeof(value)
            )
        except Exception:
            ctypes.windll.dwmapi.DwmSetWindowAttribute(
                hwnd, 19, byref(value), sizeof(value)
            )
    except Exception:
        pass



