# ─────────────────────────────────────────────
#  Persistence
# ─────────────────────────────────────────────
def merge_duplicate_tickers(tokens):
    """Mescla entradas com o mesmo ticker em um único token, preservando todos os trades."""
    merged = {}
    order  = []
    for t in tokens:
        ticker = t["ticker"]
        if ticker not in merged:
            merged[ticker] = dict(t)
            merged[ticker]["trades"] = list(t.get("trades", []))
            order.append(ticker)
        else:
            merged[ticker]["trades"].extend(t.get("trades", []))
            # mantém o preço mais recente
            if t.get("price", 0):
                merged[ticker]["price"] = t["price"]
    return [merged[tk] for tk in order]

def load_data():
    if os.path.exists(DATA_FILE):
        with open(DATA_FILE) as f:
            tokens = json.load(f)
    else:
        tokens = [dict(t) for t in DEFAULT_TOKENS]
    tokens = merge_duplicate_tickers(tokens)
    return tokens

def save_data(tokens):
    with open(DATA_FILE, "w") as f: json.dump(tokens, f, indent=2)
    try:
        save_trades_csv(tokens)
    except Exception:
        pass

def load_config():
    cfg = dict(DEFAULT_CONFIG)
    if os.path.exists(CONF_FILE):
        with open(CONF_FILE) as f: cfg.update(json.load(f))
    return cfg

def save_config(cfg):
    with open(CONF_FILE, "w") as f: json.dump(cfg, f, indent=2)

CSV_FILE = os.path.join(BASE_DIR, "trades_export.csv")

def save_trades_csv(tokens):
    """Salva/atualiza o CSV interno sempre que um trade é adicionado/removido."""
    rows = _collect_trade_rows(tokens)
    with open(CSV_FILE, "w", newline="", encoding="utf-8") as f:
        w = csv.writer(f)
        w.writerow(["Ativo","Data","Quantidade","Preço Médio ($)","Capital Investido ($)"])
        for r in rows:
            w.writerow(r)

def _collect_trade_rows(tokens):
    rows = []
    for t in tokens:
        for tr in t.get("trades", []):
            qty        = tr["qty"]
            price_paid = tr["price_paid"]
            total      = qty * price_paid
            rows.append([
                t["ticker"],
                tr.get("date", ""),
                qty,
                price_paid,
                round(total, 8),
            ])
    rows.sort(key=lambda x: x[1], reverse=True)
    return rows

def export_trades_dialog(tokens, parent_window=None):
    """Abre diálogo para escolher onde salvar o CSV de exportação."""
    rows = _collect_trade_rows(tokens)
    default_name = f"trades_{datetime.datetime.now().strftime('%Y%m%d_%H%M%S')}.csv"
    path = filedialog.asksaveasfilename(
        parent=parent_window,
        title="Exportar trades",
        defaultextension=".csv",
        filetypes=[("CSV", "*.csv"), ("Todos os arquivos", "*.*")],
        initialfile=default_name,
    )
    if not path:
        return False
    with open(path, "w", newline="", encoding="utf-8") as f:
        w = csv.writer(f)
        w.writerow(["Ativo","Data","Quantidade","Preço Médio ($)","Capital Investido ($)"])
        for r in rows:
            w.writerow(r)
    return path

# ─────────────────────────────────────────────
#  Calculations
# ─────────────────────────────────────────────
def token_totals(t):
    qty      = sum(tr["qty"]                    for tr in t.get("trades", []))
    invested = sum(tr["qty"] * tr["price_paid"] for tr in t.get("trades", []))
    return qty, invested

def calc(t):
    qty, invested = token_totals(t)
    price     = t.get("price", 0)
    pos_value = price * qty
    avg_cost  = invested / qty if qty else 0
    pnl       = pos_value - invested
    ret       = (pnl / invested * 100) if invested else 0
    be_dist   = ((avg_cost - price) / price * 100) if price else 0
    return pos_value, avg_cost, pnl, ret, be_dist, qty, invested

