# ─────────────────────────────────────────────
def fmt_price(n):
    if n >= 1000: return f"${n:,.2f}"
    if n >= 1:    return f"${n:.4f}"
    return f"${n:.6f}"

def fmt_usd(n):   return f"${n:,.2f}"
def fmt_qty(n):
    if n >= 1000: return f"{n:,.2f}"
    if n >= 1:    return f"{n:.4f}"
    return f"{n:.6f}"
def sign(n): return "+" if n >= 0 else ""

