# ── Source 1: Hyperliquid ─────────────────────
def _hl_all_mids():
    payload = json.dumps({"type": "allMids"}).encode()
    req = urllib.request.Request(
        "https://api.hyperliquid.xyz/info",
        data=payload,
        headers={"Content-Type": "application/json"},
        method="POST")
    with urllib.request.urlopen(req, timeout=6) as r:
        return json.loads(r.read())

# ── Source 2: CoinGecko (free, no key) ───────
def _coingecko_price(ticker_up):
    cg_id = COINGECKO_IDS.get(ticker_up)
    if not cg_id:
        return None
    url = (f"https://api.coingecko.com/api/v3/simple/price"
           f"?ids={cg_id}&vs_currencies=usd")
    with urllib.request.urlopen(url, timeout=8) as r:
        data = json.loads(r.read())
    if cg_id in data:
        return data[cg_id]["usd"]
    return None

def _coingecko_bulk(tickers):
    ids_map = {t: COINGECKO_IDS[t] for t in tickers if t in COINGECKO_IDS}
    if not ids_map:
        return {}
    url = (f"https://api.coingecko.com/api/v3/simple/price"
           f"?ids={','.join(ids_map.values())}&vs_currencies=usd")
    with urllib.request.urlopen(url, timeout=8) as r:
        data = json.loads(r.read())
    result = {}
    for ticker, cg_id in ids_map.items():
        if cg_id in data:
            result[ticker] = data[cg_id]["usd"]
    return result

# ── Source 3: Binance (USDT pair) ────────────
def _binance_price(ticker_up):
    symbol = f"{ticker_up}USDT"
    url = f"https://api.binance.com/api/v3/ticker/price?symbol={symbol}"
    with urllib.request.urlopen(url, timeout=6) as r:
        data = json.loads(r.read())
    if "price" in data:
        return float(data["price"])
    return None

def _binance_bulk(tickers):
    url = "https://api.binance.com/api/v3/ticker/price"
    with urllib.request.urlopen(url, timeout=8) as r:
        data = json.loads(r.read())
    price_map = {item["symbol"]: float(item["price"]) for item in data}
    result = {}
    for t in tickers:
        sym = f"{t}USDT"
        if sym in price_map:
            result[t] = price_map[sym]
    return result

# ── Source 4: KuCoin (USDT pair) ─────────────
def _kucoin_price(ticker_up):
    symbol = f"{ticker_up}-USDT"
    url = f"https://api.kucoin.com/api/v1/market/orderbook/level1?symbol={symbol}"
    with urllib.request.urlopen(url, timeout=6) as r:
        data = json.loads(r.read())
    if data.get("code") == "200000" and data.get("data") and data["data"].get("price"):
        return float(data["data"]["price"])
    return None

def _kucoin_bulk(tickers):
    url = "https://api.kucoin.com/api/v1/market/allTickers"
    with urllib.request.urlopen(url, timeout=8) as r:
        data = json.loads(r.read())
    result = {}
    if data.get("code") == "200000":
        for item in data.get("data", {}).get("ticker", []):
            sym = item.get("symbol", "")
            if sym.endswith("-USDT"):
                t = sym[:-5]
                try:
                    if item.get("last"):
                        result[t] = float(item["last"])
                except (ValueError, TypeError):
                    pass
    return {t: result[t] for t in tickers if t in result}

# ── Source 5: CryptoCompare (free, no key) ───
def _cryptocompare_price(ticker_up):
    url = (f"https://min-api.cryptocompare.com/data/price"
           f"?fsym={ticker_up}&tsyms=USD")
    with urllib.request.urlopen(url, timeout=6) as r:
        data = json.loads(r.read())
    if "USD" in data:
        return float(data["USD"])
    return None

def _cryptocompare_bulk(tickers):
    fsyms = ",".join(tickers)
    url = (f"https://min-api.cryptocompare.com/data/pricemulti"
           f"?fsyms={fsyms}&tsyms=USD")
    with urllib.request.urlopen(url, timeout=8) as r:
        data = json.loads(r.read())
    result = {}
    for t in tickers:
        if t in data and "USD" in data[t]:
            result[t] = float(data[t]["USD"])
    return result

# ── Cascade: single ticker ────────────────────
SOURCES_SINGLE = [
    ("Hyperliquid",    lambda t: float(_hl_all_mids()[t]) if t in _hl_all_mids() else None),
    ("CoinGecko",      _coingecko_price),
    ("Binance",        _binance_price),
    ("KuCoin",         _kucoin_price),
    ("CryptoCompare",  _cryptocompare_price),
]

def fetch_price_single(ticker, callback):
    def run():
        ticker_up = ticker.upper()

        # Hyperliquid first (single call covers all tickers)
        try:
            mids = _hl_all_mids()
            if ticker_up in mids:
                callback(float(mids[ticker_up]), "Hyperliquid", None)
                return
        except Exception:
            pass

        # Fallbacks in order
        for source_name, fn in [
            ("CoinGecko",     lambda t: _coingecko_price(t)),
            ("Binance",       lambda t: _binance_price(t)),
            ("KuCoin",        lambda t: _kucoin_price(t)),
            ("CryptoCompare", lambda t: _cryptocompare_price(t)),
        ]:
            try:
                price = fn(ticker_up)
                if price is not None:
                    callback(price, source_name, None)
                    return
            except Exception:
                pass

        callback(None, None, "not_found")
    threading.Thread(target=run, daemon=True).start()

def fetch_prices_bulk(tickers, callback):
    def run():
        prices = {}

        # 1. Hyperliquid
        try:
            mids = _hl_all_mids()
            for t in tickers:
                if t in mids:
                    prices[t] = float(mids[t])
        except Exception:
            pass

        missing = [t for t in tickers if t not in prices]
        if not missing:
            callback(prices); return

        # 2. CoinGecko
        try:
            found = _coingecko_bulk(missing)
            prices.update(found)
        except Exception:
            pass

        missing = [t for t in tickers if t not in prices]
        if not missing:
            callback(prices); return

        # 3. Binance
        try:
            found = _binance_bulk(missing)
            prices.update(found)
        except Exception:
            pass

        missing = [t for t in tickers if t not in prices]
        if not missing:
            callback(prices); return

        # 4. KuCoin
        try:
            found = _kucoin_bulk(missing)
            prices.update(found)
        except Exception:
            pass

        missing = [t for t in tickers if t not in prices]
        if not missing:
            callback(prices); return

        # 5. CryptoCompare
        try:
            found = _cryptocompare_bulk(missing)
            prices.update(found)
        except Exception:
            pass

        callback(prices)
    threading.Thread(target=run, daemon=True).start()

