# ERC-20 Transfer topic0
_ERC20_TRANSFER_TOPIC = "0xddf252ad1be2c89b69c2b068fc378daa952ba7f163c4a11628f55a4df523b3ef"

def _http_json(url, data=None, headers=None, timeout=10):
    """Minimal JSON HTTP helper."""
    hdrs = {"Content-Type": "application/json", "User-Agent": "MadTrade/1.0"}
    if headers:
        hdrs.update(headers)
    body = json.dumps(data).encode() if data else None
    req  = urllib.request.Request(url, data=body, headers=hdrs,
                                  method="POST" if body else "GET")
    with urllib.request.urlopen(req, timeout=timeout) as r:
        return json.loads(r.read())

def _extract_tx_hash(raw: str) -> str:
    """Pull the bare 0x… hash out of a URL or return raw if already a hash."""
    raw = raw.strip()
    # Solana: 88-char base58
    if not raw.startswith("0x") and "/" not in raw and len(raw) >= 43:
        return raw
    # Extract last path segment that looks like a hex hash
    for part in reversed(raw.split("/")):
        part = part.split("?")[0].strip()
        if part.startswith("0x") and len(part) >= 64:
            return part
        if len(part) == 64 and all(c in "0123456789abcdefABCDEF" for c in part):
            return "0x" + part
    return raw

def _evm_rpc(rpc_url, method, params):
    payload = {"jsonrpc": "2.0", "id": 1, "method": method, "params": params}
    return _http_json(rpc_url, data=payload)["result"]

def _hex_to_int(h):
    if h is None: return 0
    return int(h, 16)

def _wei_to_eth(wei): return wei / 1e18

# ── CoinGecko historical price ────────────────
_CG_PLATFORM = {
    "Ethereum":  "ethereum",
    "BNB Chain": "binance-smart-chain",
    "Base":      "base",
    "Arbitrum":  "arbitrum-one",
    "Polygon":   "polygon-pos",
    "HyperEVM":  None,
    "Solana":    "solana",
}

def _coingecko_token_price_at(contract: str, platform: str, ts: int) -> float | None:
    """Get USD price of a token contract at a given Unix timestamp via CoinGecko."""
    try:
        date_str = datetime.datetime.utcfromtimestamp(ts).strftime("%d-%m-%Y")
        url = (f"https://api.coingecko.com/api/v3/coins/{platform}"
               f"/contract/{contract.lower()}/market_chart/range"
               f"?vs_currency=usd&from={ts-3600}&to={ts+3600}")
        data = _http_json(url, timeout=12)
        prices = data.get("prices", [])
        if prices:
            return float(prices[len(prices)//2][1])
    except Exception:
        pass
    # fallback: simple/price by contract
    try:
        url2 = (f"https://api.coingecko.com/api/v3/simple/token_price/{platform}"
                f"?contract_addresses={contract.lower()}&vs_currencies=usd")
        d2 = _http_json(url2, timeout=8)
        for v in d2.values():
            if "usd" in v:
                return float(v["usd"])
    except Exception:
        pass
    return None

def _coingecko_coin_price_at(coin_id: str, ts: int) -> float | None:
    """Get USD price of a known CoinGecko coin at a timestamp."""
    try:
        date_str = datetime.datetime.utcfromtimestamp(ts).strftime("%d-%m-%Y")
        url = f"https://api.coingecko.com/api/v3/coins/{coin_id}/history?date={date_str}&localization=false"
        d = _http_json(url, timeout=10)
        return float(d["market_data"]["current_price"]["usd"])
    except Exception:
        pass
    return None

# ── EVM token symbol / decimals (via scan API or RPC) ────────────────────────
def _erc20_symbol_decimals(contract: str, network: str) -> tuple[str, int]:
    """Return (symbol, decimals) for an ERC-20 contract."""
    # Try scan API first
    ep = _EXPLORERS.get(network, {})
    scan = ep.get("scan_api")
    if scan:
        try:
            url = (f"{scan}?module=token&action=tokeninfo"
                   f"&contractaddress={contract}&apikey={ep['scan_key'] or 'YourApiKeyToken'}")
            d = _http_json(url, timeout=8)
            if d.get("status") == "1" and d.get("result"):
                r = d["result"][0] if isinstance(d["result"], list) else d["result"]
                return r.get("symbol","?"), int(r.get("divisor", 18))
        except Exception:
            pass
    # Fallback: RPC eth_call for symbol() and decimals()
    rpc = ep.get("rpc","")
    if rpc:
        try:
            # symbol()
            sym_hex = _evm_rpc(rpc, "eth_call", [
                {"to": contract, "data": "0x95d89b41"}, "latest"])
            symbol = bytes.fromhex(sym_hex[2:]).decode("utf-8", errors="ignore").rstrip("\x00").strip()
            # decimals()
            dec_hex = _evm_rpc(rpc, "eth_call", [
                {"to": contract, "data": "0x313ce567"}, "latest"])
            decimals = int(dec_hex, 16)
            if symbol:
                return symbol, decimals
        except Exception:
            pass
    return "?", 18

# ── EVM Transaction Analysis ─────────────────────────────────────────────────
def _analyze_evm_tx(tx_hash: str, network: str) -> dict:
    ep   = _EXPLORERS[network]
    rpc  = ep["rpc"]
    scan = ep.get("scan_api")

    # 1. Fetch receipt + tx
    receipt = _evm_rpc(rpc, "eth_getTransactionReceipt", [tx_hash])
    tx      = _evm_rpc(rpc, "eth_getTransactionByHash",  [tx_hash])
    if not receipt or not tx:
        raise ValueError("Transaction not found or pending.")

    block_num = receipt.get("blockNumber") or tx.get("blockNumber")
    block     = _evm_rpc(rpc, "eth_getBlockByNumber", [block_num, False])
    ts        = _hex_to_int(block["timestamp"])
    dt_str    = datetime.datetime.utcfromtimestamp(ts).strftime("%Y-%m-%d %H:%M:%S")

    gas_used  = _hex_to_int(receipt.get("gasUsed"))
    gas_price = _hex_to_int(tx.get("gasPrice") or tx.get("maxFeePerGas") or "0x0")
    gas_fee_eth = _wei_to_eth(gas_used * gas_price)

    from_addr = (tx.get("from") or "").lower()
    to_addr   = (tx.get("to")   or "").lower()
    value_wei = _hex_to_int(tx.get("value", "0x0"))

    logs = receipt.get("logs", [])

    # 2. Parse ERC-20 Transfer events
    transfers = []
    for log in logs:
        topics = log.get("topics", [])
        if len(topics) >= 3 and topics[0].lower() == _ERC20_TRANSFER_TOPIC:
            contract = log["address"].lower()
            sender   = ("0x" + topics[1][-40:]).lower()
            receiver = ("0x" + topics[2][-40:]).lower()
            raw_val  = _hex_to_int(log["data"])
            sym, dec = _erc20_symbol_decimals(contract, network)
            amount   = raw_val / (10 ** dec)
            transfers.append({
                "contract": contract,
                "symbol":   sym,
                "decimals": dec,
                "from":     sender,
                "to":       receiver,
                "amount":   amount,
            })

    # 3. Identify what the user sent / received
    # Native coin names
    native = {"Ethereum":"ETH","BNB Chain":"BNB","Base":"ETH",
               "Arbitrum":"ETH","Polygon":"POL","HyperEVM":"HYPE"}.get(network,"ETH")

    token_bought  = None  # symbol
    amount_bought = 0.0
    contract_bought = None
    token_sold    = None
    amount_sold   = 0.0

    # Transfers TO the user's wallet = tokens received
    incoming = [t for t in transfers if t["to"] == from_addr]
    # Transfers FROM the user's wallet = tokens sent
    outgoing = [t for t in transfers if t["from"] == from_addr]

    if incoming:
        # Take the largest non-stable incoming transfer as the "bought" token
        non_stable_in = [t for t in incoming if t["symbol"].upper() not in _STABLECOINS]
        chosen = (non_stable_in or incoming)
        chosen.sort(key=lambda x: x["amount"], reverse=True)
        best = chosen[0]
        token_bought    = best["symbol"]
        amount_bought   = best["amount"]
        contract_bought = best["contract"]

    if outgoing:
        non_stable_out = [t for t in outgoing if t["symbol"].upper() not in _STABLECOINS]
        chosen_out = (non_stable_out if non_stable_out else outgoing)
        chosen_out.sort(key=lambda x: x["amount"], reverse=True)
        best_out = chosen_out[0]
        token_sold  = best_out["symbol"]
        amount_sold = best_out["amount"]
    elif value_wei > 0:
        token_sold  = native
        amount_sold = _wei_to_eth(value_wei)

    # If only native coin sent, no ERC-20 swap detected → treat as native buy
    if not token_bought and value_wei > 0:
        token_bought  = native
        amount_bought = _wei_to_eth(value_wei)
        contract_bought = None

    # 4. USD value at time of tx
    cg_platform = _CG_PLATFORM.get(network)
    usd_total = None

    # Try stable side first
    for tr in (outgoing or []) + (incoming or []):
        if tr["symbol"].upper() in _STABLECOINS:
            usd_total = tr["amount"]
            break

    if usd_total is None and contract_bought and cg_platform:
        price_each = _coingecko_token_price_at(contract_bought, cg_platform, ts)
        if price_each and amount_bought:
            usd_total = price_each * amount_bought

    if usd_total is None:
        # Try native coin price at timestamp
        native_cg = {"ETH":"ethereum","BNB":"binancecoin","POL":"matic-network",
                      "HYPE":"hyperliquid"}.get(native)
        if native_cg and amount_sold:
            native_price = _coingecko_coin_price_at(native_cg, ts)
            if native_price:
                usd_total = native_price * amount_sold

    avg_price = (usd_total / amount_bought) if (usd_total and amount_bought) else None

    # Gas fee in USD
    gas_usd = None
    native_cg = {"ETH":"ethereum","BNB":"binancecoin","POL":"matic-network",
                  "HYPE":"hyperliquid"}.get(native)
    if native_cg:
        np = _coingecko_coin_price_at(native_cg, ts)
        if np:
            gas_usd = gas_fee_eth * np

    return {
        "network":        network,
        "tx_hash":        tx_hash,
        "datetime":       dt_str,
        "wallet":         from_addr,
        "token_bought":   token_bought  or "?",
        "amount_bought":  amount_bought,
        "token_sold":     token_sold,
        "amount_sold":    amount_sold,
        "usd_total":      usd_total,
        "avg_price_usd":  avg_price,
        "gas_fee_native": gas_fee_eth,
        "gas_fee_usd":    gas_usd,
        "native_symbol":  native,
    }

# ── Solana Transaction Analysis ───────────────────────────────────────────────
def _analyze_solana_tx(tx_hash: str) -> dict:
    payload = {
        "jsonrpc": "2.0", "id": 1,
        "method": "getTransaction",
        "params": [tx_hash, {"encoding": "jsonParsed", "maxSupportedTransactionVersion": 0}]
    }
    d = _http_json(_SOLANA_RPC, data=payload, timeout=15)
    tx = d.get("result")
    if not tx:
        raise ValueError("Solana transaction not found.")

    ts     = tx.get("blockTime", 0)
    dt_str = datetime.datetime.utcfromtimestamp(ts).strftime("%Y-%m-%d %H:%M:%S") if ts else "?"
    meta   = tx.get("meta", {})
    fee_lamports = meta.get("fee", 0)
    gas_fee_sol  = fee_lamports / 1e9

    # Account keys
    account_keys = []
    msg = tx.get("transaction", {}).get("message", {})
    for ak in msg.get("accountKeys", []):
        if isinstance(ak, dict):
            account_keys.append(ak.get("pubkey",""))
        else:
            account_keys.append(str(ak))
    signer = account_keys[0] if account_keys else "?"

    # Token balance changes
    pre_balances  = {b["accountIndex"]: b for b in meta.get("preTokenBalances",  [])}
    post_balances = {b["accountIndex"]: b for b in meta.get("postTokenBalances", [])}

    all_indices = set(pre_balances) | set(post_balances)
    token_bought = None; amount_bought = 0.0; mint_bought = None
    token_sold   = None; amount_sold   = 0.0

    for idx in all_indices:
        pre  = pre_balances.get(idx,  {})
        post = post_balances.get(idx, {})
        mint = post.get("mint") or pre.get("mint","")
        sym  = (post.get("uiTokenAmount",{}).get("symbol") or
                pre.get("uiTokenAmount",{}).get("symbol") or
                mint[:8])
        pre_amt  = float((pre.get("uiTokenAmount",{})  or {}).get("uiAmountString", 0) or 0)
        post_amt = float((post.get("uiTokenAmount",{}) or {}).get("uiAmountString", 0) or 0)
        delta    = post_amt - pre_amt
        if delta > 1e-9:  # received
            if not token_bought or delta > amount_bought:
                token_bought  = sym; amount_bought = delta; mint_bought = mint
        elif delta < -1e-9:  # sent
            if not token_sold or abs(delta) > amount_sold:
                token_sold = sym; amount_sold = abs(delta)

    # USD value
    usd_total = None; avg_price = None
    if token_sold and token_sold.upper() in _STABLECOINS:
        usd_total = amount_sold
    elif token_bought and token_bought.upper() in _STABLECOINS:
        usd_total = amount_bought

    if usd_total is None and mint_bought:
        try:
            url = (f"https://api.coingecko.com/api/v3/simple/token_price/solana"
                   f"?contract_addresses={mint_bought}&vs_currencies=usd")
            cg = _http_json(url, timeout=8)
            for v in cg.values():
                if "usd" in v:
                    p = float(v["usd"])
                    usd_total = p * amount_bought
                    break
        except Exception:
            pass

    if usd_total and amount_bought:
        avg_price = usd_total / amount_bought

    sol_price = _coingecko_coin_price_at("solana", ts) if ts else None
    gas_usd   = (gas_fee_sol * sol_price) if sol_price else None

    return {
        "network":        "Solana",
        "tx_hash":        tx_hash,
        "datetime":       dt_str,
        "wallet":         signer,
        "token_bought":   token_bought or "?",
        "amount_bought":  amount_bought,
        "token_sold":     token_sold,
        "amount_sold":    amount_sold,
        "usd_total":      usd_total,
        "avg_price_usd":  avg_price,
        "gas_fee_native": gas_fee_sol,
        "gas_fee_usd":    gas_usd,
        "native_symbol":  "SOL",
    }

def _classify_error(exc: Exception, raw_input: str, network: str) -> str:
    """Map a low-level exception to a translation key the UI can display."""
    msg = str(exc).lower()
    raw = raw_input.strip()

    # Unsupported network (should not happen via UI but guard anyway)
    if network not in _EXPLORERS and network != "Solana":
        return "err_unsupported_net"

    # Invalid hash / URL format checks
    tx_hash = _extract_tx_hash(raw)
    is_evm_hash    = tx_hash.startswith("0x") and len(tx_hash) == 66
    is_solana_hash = (not tx_hash.startswith("0x") and
                      43 <= len(tx_hash) <= 90 and
                      all(c in "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz"
                          for c in tx_hash))
    if "/" in raw and not tx_hash.startswith("0x") and not is_solana_hash:
        return "err_invalid_url"
    if not is_evm_hash and not is_solana_hash:
        return "err_invalid_hash"

    # Network mismatch (EVM hash on Solana or vice-versa)
    if network == "Solana" and is_evm_hash:
        return "err_wrong_network"
    if network != "Solana" and is_solana_hash:
        return "err_wrong_network"

    # Transaction not found / null result
    if any(k in msg for k in ("not found", "none", "null", "pending", "noneType")):
        if "pending" in msg:
            return "err_pending_tx"
        return "err_tx_not_found"

    # Wrong network (transaction exists but on a different chain)
    if any(k in msg for k in ("wrong network", "chain", "mismatch")):
        return "err_wrong_network"

    # API / network failures
    if any(k in msg for k in ("timeout", "urlopen", "http", "connection",
                               "ssl", "refused", "remote", "socket", "403", "429", "500")):
        return "err_api_fail"

    # Generic fallback: show raw message
    return "err_api_fail"

def analyze_transaction(raw_input: str, network: str, callback):
    """
    Analyze a blockchain transaction in a background thread.
    callback(result_dict, error_key, error_detail)
      result_dict — populated on success, None on error
      error_key   — i18n key (e.g. 'err_tx_not_found'), None on success
      error_detail — raw exception string for dev info, None on success
    """
    def run():
        try:
            tx_hash = _extract_tx_hash(raw_input)
            # Pre-flight: basic format validation
            is_evm    = tx_hash.startswith("0x") and len(tx_hash) == 66
            is_solana = (not tx_hash.startswith("0x") and 43 <= len(tx_hash) <= 90)
            if not is_evm and not is_solana:
                if "/" in raw_input.strip():
                    callback(None, "err_invalid_url", None)
                else:
                    callback(None, "err_invalid_hash", None)
                return
            if network not in _EXPLORERS and network != "Solana":
                callback(None, "err_unsupported_net", None)
                return
            if network == "Solana" and is_evm:
                callback(None, "err_wrong_network", None)
                return
            if network != "Solana" and is_solana:
                callback(None, "err_wrong_network", None)
                return

            if network == "Solana":
                result = _analyze_solana_tx(tx_hash)
            else:
                result = _analyze_evm_tx(tx_hash, network)
            callback(result, None, None)
        except Exception as exc:
            key = _classify_error(exc, raw_input, network)
            callback(None, key, str(exc))
    threading.Thread(target=run, daemon=True).start()


GREEN  = "#00e5a0"
RED    = "#ff5252"

def pnl_color(n): return GREEN if n >= 0 else RED
def be_color(be): return GREEN if be <= 0 else RED

def theme_fg(cfg):
    """Main text colour depending on theme."""
    return "#1a1a1a" if cfg.get("theme") == "light" else "#f0f0f0"

def theme_muted(cfg):
    return "#888888" if cfg.get("theme") == "light" else "#555555"

def theme_border(cfg):
    return "#cccccc" if cfg.get("theme") == "light" else "#252525"

# ─────────────────────────────────────────────
#  Scrollable frame helper
# ─────────────────────────────────────────────
class ScrollableFrame(tk.Frame):
    def __init__(self, parent, bg, sb_bg=None, sb_fg=None, **kw):
        super().__init__(parent, bg=bg, **kw)
        self.canvas = tk.Canvas(self, bg=bg, highlightthickness=0, bd=0)
        _sb_bg = sb_bg or bg
        _sb_fg = sb_fg or "#444444"
        self.sb = tk.Scrollbar(self, orient="vertical", command=self.canvas.yview,
                               bg=_sb_bg, troughcolor=_sb_bg, activebackground=_sb_fg,
                               relief="flat", bd=0, width=8)
        self.inner = tk.Frame(self.canvas, bg=bg)
        self.inner.bind("<Configure>",
            lambda e: self.canvas.configure(scrollregion=(0, 0, e.width, e.height)))
        self._win_id = self.canvas.create_window((0,0), window=self.inner, anchor="nw")
        self.canvas.configure(yscrollcommand=self.sb.set)
        self.canvas.pack(side="left", fill="both", expand=True)
        self.sb.pack(side="right", fill="y")
        self.canvas.bind("<MouseWheel>", self._scroll)
        self.inner.bind("<MouseWheel>", self._scroll)
        # make canvas width follow frame width and keep scrollregion in sync
        def _on_canvas_configure(e):
            self.canvas.itemconfig(self._win_id, width=e.width)
            self.canvas.update_idletasks()
            ih = self.inner.winfo_reqheight()
            self.canvas.configure(scrollregion=(0, 0, e.width, ih))
        self.canvas.bind("<Configure>", _on_canvas_configure)

    def _scroll(self, e):
        self.canvas.yview_scroll(int(-1*(e.delta/120)), "units")

    def bind_scroll_recursive(self, widget):
        """Bind mousewheel on widget and all its descendants."""
        widget.bind("<MouseWheel>", self._scroll, add="+")
        for child in widget.winfo_children():
            self.bind_scroll_recursive(child)

# ─────────────────────────────────────────────
#  Main App
# ─────────────────────────────────────────────
class MadTrade:
    def __init__(self, root):
        self.root      = root
        self.tokens    = load_data()
        self.cfg       = load_config()
        self.expanded  = set()
        self._refresh_job    = None
        self._ticker_after   = None
        self._add_token_win  = None  # Toplevel for add-token form
        self._rendering      = False  # guard contra renders simultâneos
        self._active_tab     = "dashboard"  # "dashboard" | "history"

        C = self.cfg
        global _FONT_SCALE
        _FONT_SCALE = float(C.get("font_scale", 1.0))
        self.root.title("MadTrade")
        self.root.configure(bg=C["bg"])
        self.root.resizable(True, True)

        # ── set window icon ──
        self._set_icon()

        # restore geometry — no minsize restriction
        sw, sh = self.root.winfo_screenwidth(), self.root.winfo_screenheight()
        w = C.get("win_w", 520); h = C.get("win_h", 640)
        x = C.get("win_x") or (sw - w - 40)
        y = C.get("win_y") or (sh - h - 60)
        self.root.geometry(f"{w}x{h}+{x}+{y}")
        # No minsize — user can make it as small as they want

        self.root.protocol("WM_DELETE_WINDOW", self._quit)
        self.root.bind("<Configure>", self._on_resize)

        self._build_ui()
        self.render()
        self._schedule_refresh()

    # ── icon ──────────────────────────────────
    def _set_icon(self):
        import os
        import ctypes

        try:
            ctypes.windll.shell32.SetCurrentProcessExplicitAppUserModelID("MadTrade.App")
        except Exception:
            pass

        try:
            icon_path = os.path.join(BASE_DIR, "madicon.ico")
            self.root.iconbitmap(icon_path)
        except Exception as e:
            print("Erro ao carregar ícone:", e)

    def S(self, key):
        """Return translated string for current language."""
        lang = self.cfg.get("lang", "pt")
        return STRINGS[lang].get(key, STRINGS["pt"][key])

    def C(self):
        return self.cfg

    # ── geometry save ─────────────────────────
    def _on_resize(self, e):
        if e.widget is self.root:
            self.cfg.update({"win_w": self.root.winfo_width(),
                             "win_h": self.root.winfo_height(),
                             "win_x": self.root.winfo_x(),
                             "win_y": self.root.winfo_y()})

    def _quit(self):
        self.cfg.update({"win_w": self.root.winfo_width(),
                         "win_h": self.root.winfo_height(),
                         "win_x": self.root.winfo_x(),
                         "win_y": self.root.winfo_y()})
        save_config(self.cfg)
        self.root.destroy()

    # ── theme & lang toggles ──────────────────
    def _change_font_scale(self, delta):
        global _FONT_SCALE
        current = float(self.cfg.get("font_scale", 1.0))
        new_scale = round(max(0.7, min(1.5, current + delta)), 1)
        if new_scale == current:
            return
        self.cfg["font_scale"] = new_scale
        _FONT_SCALE = new_scale
        save_config(self.cfg)
        self._close_add_token_win()
        self._rebuild()

    def _toggle_theme(self):
        current = self.cfg.get("theme", "dark")
        new_theme = "light" if current == "dark" else "dark"
        self.cfg["theme"] = new_theme
        colors = LIGHT_COLORS if new_theme == "light" else DARK_COLORS
        self.cfg.update(colors)
        save_config(self.cfg)
        self._close_add_token_win()
        self._rebuild()

    def _toggle_lang(self):
        # Ciclo entre idiomas disponíveis — adicione novos em STRINGS e aqui
        langs = list(STRINGS.keys())  # ["pt", "en", ...]
        current = self.cfg.get("lang", langs[0])
        idx = langs.index(current) if current in langs else 0
        self.cfg["lang"] = langs[(idx + 1) % len(langs)]
        save_config(self.cfg)
        self._close_add_token_win()
        self._rebuild()

    def _close_add_token_win(self):
        if self._add_token_win and self._add_token_win.winfo_exists():
            self._add_token_win.destroy()
        self._add_token_win = None

    def _rebuild(self):
        """Destroy and recreate all UI widgets then re-render."""
        for w in self.root.winfo_children():
            w.destroy()
        self.root.configure(bg=self.cfg["bg"])
        self._add_token_win = None
        self._add_trade_visible = {}
        self._build_ui()
        self.render()

    # ── build skeleton ─────────────────────────
    def _build_ui(self):
        C = self.cfg
        TEXT   = theme_fg(C)
        MUTED  = theme_muted(C)
        BORDER = theme_border(C)

        # ── top bar (two rows: summary on top, buttons below) ──
